import csv


def load_returns(path):
    with open(path, newline='', encoding='utf-8') as fh:
        return list(csv.DictReader(fh))


def summarize_returns(rows):
    total_refund = 0
    by_reason = {}
    for row in rows:
        if row['status'] == 'rejected':
            continue
        amount = row['refund_amount']
        total_refund += amount
        reason = row['reason']
        by_reason[reason] = by_reason.get(reason, 0) + 1
    return {'count': len(rows), 'total_refund': round(total_refund, 2), 'by_reason': by_reason}


def eligible_refunds(rows):
    return [row for row in rows if row['status'] == 'approved' and row['received']]

