from returns.pipeline import load_returns, summarize_returns, eligible_refunds


def test_summary_excludes_rejected_and_uses_numbers():
    rows = load_returns('data/returns.csv')
    assert summarize_returns(rows) == {'count': 3, 'total_refund': 80.75, 'by_reason': {'damaged': 2, 'wrong_item': 1}}


def test_eligible_refunds_only_approved_and_received_true():
    rows = load_returns('data/returns.csv')
    eligible = eligible_refunds(rows)
    assert [row['id'] for row in eligible] == ['R1', 'R4']
